function useReducerWithMiddleware(reducer, initialState, middlewares) {
  const [state, dispatch] = useReducer(reducer, initialState);
  const stateRef = useRef(state);
  stateRef.current = state;

  const dispatchWithMiddleware = useCallback((action) => {
    const chain = middlewares.map(mw => mw(stateRef));
    let finalDispatch = dispatch;
    for (let i = chain.length - 1; i >= 0; i--) {
      finalDispatch = chain[i](finalDispatch);
    }
    return finalDispatch(action);
  }, [middlewares]);

  return [state, dispatchWithMiddleware];
}

