function useOptimistic(currentState, updateFn) {
  const [optimisticState, setOptimisticState] = useState(currentState);
  const pendingRef = useRef(false);

  useEffect(() => {
    if (!pendingRef.current) {
      setOptimisticState(currentState);
    }
  }, [currentState]);

  const addOptimistic = useCallback((optimisticValue) => {
    pendingRef.current = true;
    setOptimisticState(prev => updateFn(prev, optimisticValue));
  }, [updateFn]);

  const resolve = useCallback(() => {
    pendingRef.current = false;
  }, []);

  return [optimisticState, addOptimistic, resolve];
}

