function createTrackedState(initialState) {
  const subscribers = new Map();
  const state = new Proxy(initialState, {
    get(target, prop) {
      const currentComponent = getCurrentRenderingFiber();
      if (currentComponent) {
        if (!subscribers.has(prop)) subscribers.set(prop, new Set());
        subscribers.get(prop).add(currentComponent);
      }
      return target[prop];
    },
    set(target, prop, value) {
      target[prop] = value;
      subscribers.get(prop)?.forEach(component => {
        scheduleRerender(component);
      });
      return true;
    }
  });
  return state;
}

function useOptimisticUpdate(serverState, submitFn) {
  const [optimistic, setOptimistic] = useState(serverState);
  const pendingRef = useRef([]);

  useEffect(() => {
    setOptimistic(prev => {
      return pendingRef.current.reduce(
        (state, update) => update.apply(state),
        serverState
      );
    });
  }, [serverState]);

  const apply = useCallback(async (update) => {
    pendingRef.current.push(update);
    setOptimistic(prev => update.apply(prev));
    try {
      await submitFn(update);
    } catch (e) {
      pendingRef.current = pendingRef.current.filter(u => u !== update);
      setOptimistic(prev => {
        return pendingRef.current.reduce(
          (state, u) => u.apply(state),
          serverState
        );
      });
    }
  }, [serverState, submitFn]);

  return [optimistic, apply];
}

function useIntersectionObserver(options) {
  const [entry, setEntry] = useState(null);
  const [node, setNode] = useState(null);
  const observer = useRef(null);

  useEffect(() => {
    if (observer.current) observer.current.disconnect();
    if (!node) return;

    observer.current = new IntersectionObserver(
      ([entry]) => setEntry(entry),
      options
    );
    observer.current.observe(node);

    return () => observer.current.disconnect();
  }, [node, options?.threshold, options?.root, options?.rootMargin]);

  return [setNode, entry];
}

function useStoreSelector(store, selector, equalityFn = Object.is) {
  const [, forceRender] = useReducer(c => c + 1, 0);
  const selectedRef = useRef();
  const selectorRef = useRef(selector);
  const equalityFnRef = useRef(equalityFn);

  const checkForUpdates = useCallback(() => {
    const newSelected = selectorRef.current(store.getState());
    if (equalityFnRef.current(newSelected, selectedRef.current)) return;
    selectedRef.current = newSelected;
    forceRender();
  }, [store]);

  useEffect(() => {
    selectorRef.current = selector;
    equalityFnRef.current = equalityFn;
    checkForUpdates();
  });

  useEffect(() => {
    return store.subscribe(checkForUpdates);
  }, [store, checkForUpdates]);

  return selectedRef.current ?? selector(store.getState());
}

function useHydrationSafe(clientValue, serverValue) {
  const [value, setValue] = useState(serverValue);
  const [hydrated, setHydrated] = useState(false);

  useEffect(() => {
    setHydrated(true);
  }, []);

  useEffect(() => {
    if (hydrated) {
      setValue(clientValue);
    }
  }, [hydrated, clientValue]);

  return value;
}

