function createContext(defaultValue) {
  const context = {
    _currentValue: defaultValue,
    Provider: null,
    Consumer: null,
  };

  context.Provider = function Provider({ value, children }) {
    // In real React, this creates a fiber node that stores the value
    // and propagates changes to consumer fibers
    context._currentValue = value;
    return children;
  };

  context.Consumer = function Consumer({ children }) {
    return children(context._currentValue);
  };

  return context;
}

