// Simplified React-style scheduler
const taskQueue = [];
const timerQueue = [];
let isPerformingWork = false;

function scheduleCallback(priorityLevel, callback, options) {
  const currentTime = performance.now();
  const startTime = options?.delay ? currentTime + options.delay : currentTime;
  const timeout = priorityLevelToTimeout(priorityLevel);
  const expirationTime = startTime + timeout;

  const newTask = { callback, priorityLevel, startTime, expirationTime, sortIndex: -1 };

  if (startTime > currentTime) {
    newTask.sortIndex = startTime;
    push(timerQueue, newTask); // delayed task
    if (peek(taskQueue) === null && newTask === peek(timerQueue)) {
      requestHostTimeout(handleTimeout, startTime - currentTime);
    }
  } else {
    newTask.sortIndex = expirationTime;
    push(taskQueue, newTask); // ready task
    if (!isPerformingWork) {
      isPerformingWork = true;
      requestHostCallback(flushWork);
    }
  }
}

function commitRoot(root) {
  const finishedWork = root.finishedWork;

  // Phase 1: Before mutation (read layout before changes)
  commitBeforeMutationEffects(finishedWork);

  // Phase 2: Mutation (DOM changes)
  commitMutationEffects(root, finishedWork);

  // Swap trees
  root.current = finishedWork;

  // Phase 3: Layout (run useLayoutEffect, measure DOM)
  commitLayoutEffects(finishedWork, root);

  // Schedule passive effects (useEffect)
  scheduleCallback(NormalPriority, () => {
    flushPassiveEffects();
  });
}
